/**
 * SpinWheelDraw.js
 * ─────────────────────────────────────────────────────────────────────────────
 * Drop-in RESPONSIVE Lucky Draw component for ChitFund Pro.
 * 
 * FEATURES:
 * 1. Auto-Draw (Spin)
 * 2. Manual Select (Admin Override)
 * 3. Last Member Auto-Assign
 * 4. High-Quality Winner Poster System (Download/Share)
 * ❌ No video recording (simplified UX)
 */
 
import React, {
  useRef, useEffect, useState, useCallback,
} from 'react';
import api from '../../utils/api';
import toast from 'react-hot-toast';
import html2canvas from 'html2canvas';

const SPIN_DURATION = 10000;
const MIN_ROTATIONS = 10;
const WHEEL_SIZE    = 350;  
const RADIUS        = 160;    
const CENTER        = WHEEL_SIZE / 2;

const SEG_PALETTES = [
  { bg: '#581c87', text: '#fde68a', border: '#7e22ce' },
  { bg: '#f59e0b', text: '#1c1917', border: '#d97706' },
  { bg: '#6d28d9', text: '#fef3c7', border: '#7c3aed' },
  { bg: '#b45309', text: '#1c1917', border: '#d97706' },
  { bg: '#7e22ce', text: '#fde68a', border: '#9333ea' },
  { bg: '#92400e', text: '#fef9c3', border: '#b45309' },
  { bg: '#4c1d95', text: '#f5d0fe', border: '#6d28d9' },
  { bg: '#78350f', text: '#fef3c7', border: '#92400e' },
];

function easeOut(t) { return 1 - Math.pow(1 - t, 5); }
function truncateName(name, maxChars = 14) {
  if (!name) return '—';
  return name.length > maxChars ? name.slice(0, maxChars - 1) + '…' : name;
}
function initials(name) {
  if (!name) return '?';
  return name.split(' ').map(w => w[0]).join('').slice(0, 2).toUpperCase();
}

let confettiFn = null;
function loadConfetti() {
  return new Promise(resolve => {
    if (confettiFn) { resolve(confettiFn); return; }
    const s = document.createElement('script');
    s.src = 'https://cdn.jsdelivr.net/npm/canvas-confetti@1.9.2/dist/confetti.browser.min.js';
    s.onload = () => { confettiFn = window.confetti; resolve(confettiFn); };
    s.onerror = () => resolve(null);
    document.head.appendChild(s);
  });
}

function drawWheel(canvas, members, rotationRad) {
  if (!canvas || members.length === 0) return;
  const ctx = canvas.getContext('2d');
  const n = members.length;
  const sliceAngle = (2 * Math.PI) / n;
  ctx.clearRect(0, 0, WHEEL_SIZE, WHEEL_SIZE);

  const glow = ctx.createRadialGradient(CENTER, CENTER, RADIUS - 6, CENTER, CENTER, RADIUS + 18);
  glow.addColorStop(0, 'rgba(192,38,211,0.55)');
  glow.addColorStop(1, 'rgba(192,38,211,0)');
  ctx.beginPath(); ctx.arc(CENTER, CENTER, RADIUS + 18, 0, 2 * Math.PI); ctx.fillStyle = glow; ctx.fill();

  for (let i = 0; i < n; i++) {
    const startAngle = rotationRad + i * sliceAngle - Math.PI / 2;
    const endAngle   = startAngle + sliceAngle;
    const pal        = SEG_PALETTES[i % SEG_PALETTES.length];
    ctx.beginPath(); ctx.moveTo(CENTER, CENTER); ctx.arc(CENTER, CENTER, RADIUS, startAngle, endAngle); ctx.closePath();
    ctx.fillStyle = pal.bg; ctx.fill(); ctx.strokeStyle = pal.border; ctx.lineWidth = 2; ctx.stroke();
    ctx.save();
    ctx.translate(CENTER, CENTER);
    ctx.rotate(startAngle + sliceAngle / 2);
    const fontSize = n <= 6 ? 12 : n <= 10 ? 10 : 8;
    ctx.font = `bold ${fontSize}px sans-serif`; ctx.fillStyle = pal.text; ctx.textAlign = 'right'; ctx.textBaseline = 'middle';
    const textRadius = RADIUS - 10;
    const nameStr = members[i].member?.name || members[i].name || '?';
    ctx.fillText(truncateName(nameStr, n > 10 ? 10 : 14), textRadius, 0); ctx.restore();
  }
  const hubGrad = ctx.createRadialGradient(CENTER - 6, CENTER - 6, 2, CENTER, CENTER, 30);
  hubGrad.addColorStop(0, '#f9f0ff'); hubGrad.addColorStop(1, '#7e22ce');
  ctx.beginPath(); ctx.arc(CENTER, CENTER, 28, 0, 2 * Math.PI); ctx.fillStyle = hubGrad; ctx.fill();
  ctx.strokeStyle = '#fbbf24'; ctx.lineWidth = 3; ctx.stroke();
  ctx.font = '20px serif'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
  ctx.fillText('🏆', CENTER, CENTER);
}

function Pointer() {
  return (
    <div style={{ position: 'absolute', top: -10, left: '50%', transform: 'translateX(-50%)', zIndex: 10, filter: 'drop-shadow(0 2px 8px rgba(245,158,11,0.7))' }}>
      <svg width="24" height="38" viewBox="0 0 28 44">
        <polygon points="14,44 0,0 28,0" fill="#f59e0b" /><polygon points="14,38 4,4 24,4" fill="#fbbf24" /><circle cx="14" cy="6" r="4" fill="#fff" />
      </svg>
    </div>
  );
}

function WinnerModal({ winner, prizeAmount, cycleLabel, onClose }) {
  if (!winner) return null;
  const winnerName = winner.member?.name || winner.name || 'Winner';
  
  const downloadPoster = async () => {
    const el = document.getElementById('winner-poster');
    if (!el) return;
    try {
      const canvas = await html2canvas(el, { 
        backgroundColor: '#ffffff', 
        scale: 3,
        onclone: (doc) => {
          // Hide all buttons in the clone before capturing
          const buttons = doc.querySelectorAll('button');
          buttons.forEach(b => b.style.display = 'none');
        }
      });
      const imgData = canvas.toDataURL('image/png');
      const a = document.createElement('a'); a.href = imgData; a.download = `Winner-${winnerName}.png`;
      document.body.appendChild(a); a.click(); document.body.removeChild(a);
    } catch(err) { toast.error('Download failed'); }
  };

  const sharePoster = async () => {
    const el = document.getElementById('winner-poster');
    if (!el) return;
    try {
      const canvas = await html2canvas(el, { 
        backgroundColor: '#ffffff', 
        scale: 2,
        onclone: (doc) => {
          const buttons = doc.querySelectorAll('button');
          buttons.forEach(b => b.style.display = 'none');
        }
      });
      canvas.toBlob(async (blob) => {
        const file = new File([blob], 'winner.png', { type: 'image/png' });
        if (navigator.share) {
          await navigator.share({ files: [file], title: 'ChitFund Winner', text: `Congratulations to ${winnerName}!` });
        } else { toast.error('Sharing not supported'); }
      });
    } catch(err) {}
  };

  return (
    <div className="fixed inset-0 flex items-center justify-center bg-black/50" style={{ zIndex: 9999999 }}>
      <div
        id="winner-poster"
        className="bg-white rounded-2xl shadow-xl p-8 w-[320px] text-center scale-in-center"
      >
        <h1 className="text-2xl font-bold mb-2">🎉 WINNER</h1>

        <h2 className="text-3xl font-bold text-green-600">
          {winnerName} ✅
        </h2>

        <p className="text-gray-500 mt-2">{cycleLabel}</p>

        <h3 className="text-xl font-semibold mt-2">₹{Number(prizeAmount).toLocaleString()}</h3>

        <div className="flex gap-2 mt-6 justify-center">
          <button onClick={downloadPoster} className="px-4 py-2 bg-slate-900 text-white rounded-lg font-bold text-sm">
            ⬇ Download
          </button>

          <button onClick={sharePoster} className="px-4 py-2 bg-brand-600 text-white rounded-lg font-bold text-sm">
            🔗 Share
          </button>
        </div>

        <button 
          className="mt-6 text-sm text-gray-500 hover:text-gray-900 font-medium tracking-widest uppercase cursor-pointer" 
          onClick={onClose}
        >
          DONE
        </button>
      </div>
    </div>
  );
}

export default function SpinWheelDraw({ eligibleMembers = [], groupId, monthIndex = 1, prizeAmount = 0, cycleLabel = '', onDrawComplete, onCloseDraw }) {
  const canvasRef = useRef(null);
  const rafRef = useRef(null);
  const rotRef = useRef(0);

  const [rotation, setRotation] = useState(0);
  const [spinning, setSpinning] = useState(false);
  const [winner, setWinner] = useState(null);
  const [showModal, setShowModal] = useState(false); // NO LONGER FORCED
  const [drawMode, setDrawMode] = useState('spin'); // 'spin' or 'manual'
  const [manualWinnerId, setManualWinnerId] = useState('');
  const [loading, setLoading] = useState(false);

  const isLastMember = eligibleMembers.length === 1;

  // Immediate force-draw canvas
  React.useLayoutEffect(() => {
    if (canvasRef.current && eligibleMembers.length > 0) {
      drawWheel(canvasRef.current, eligibleMembers, rotation);
    }
  }, [eligibleMembers, rotation, isLastMember, drawMode]);

  const spinToAngle = useCallback((targetRad, onDone) => {
    const startAngle = rotRef.current, startTime = performance.now();
    const totalSpin = MIN_ROTATIONS * 2 * Math.PI + ((targetRad - startAngle % (2*Math.PI) + 2*Math.PI) % (2*Math.PI));
    const endAngle = startAngle + totalSpin;
    const tick = (now) => {
      const progress = Math.min((now - startTime) / SPIN_DURATION, 1);
      const current = startAngle + (endAngle - startAngle) * easeOut(progress);
      rotRef.current = current; setRotation(current);
      if (progress < 1) rafRef.current = requestAnimationFrame(tick);
      else { rotRef.current = endAngle; setRotation(endAngle); onDone(); }
    };
    rafRef.current = requestAnimationFrame(tick);
  }, []);

  const revealWinner = useCallback(async (winnerData) => {
    // 1. Set winner data
    setWinner(winnerData);
    
    // 2. Open modal and celebrate
    setShowModal(true);
    const fn = await loadConfetti();
    if (fn) {
      fn({ particleCount: 200, spread: 80, origin: { y: 0.6 }, zIndex: 99999999 });
    }
    
    if (onDrawComplete) onDrawComplete(winnerData);
  }, [onDrawComplete]);

  const conductDraw = async () => {
    if (spinning || loading || eligibleMembers.length === 0) return;
    const isManual = drawMode === 'manual';
    if (isManual && !manualWinnerId && !isLastMember) return toast.error('Please select a member!');

    setLoading(true);
    try {
      const payload = { monthIndex };
      if (isManual || isLastMember) {
        payload.memberId = isManual ? manualWinnerId : eligibleMembers[0].member?._id;
      }

      const res = await api.post(`/draws/${groupId}/conduct`, payload);
      const winnerData = res.data.data;
      setLoading(false);

      if (drawMode === 'spin' && !isLastMember) {
        setSpinning(true);
        const winnerId = winnerData.member?._id || winnerData.member;
        const idx = Math.max(0, eligibleMembers.findIndex(e => (e.member?._id || e.member) === winnerId));
        const sliceAngle = (2 * Math.PI) / eligibleMembers.length;
        
        spinToAngle(-(idx * sliceAngle + sliceAngle / 2), () => {
          setSpinning(false);
          revealWinner(winnerData);
        });
      } else {
        revealWinner(winnerData);
        toast.success(isLastMember ? 'Final Draw Assigned!' : 'Winner Selected!');
      }
    } catch (err) { 
      setLoading(false); 
      toast.error(err.response?.data?.message || 'Draw failed'); 
    }
  };

  return (
    <div className="flex flex-col md:flex-row gap-8 w-full animate-in fade-in duration-500">
      <div className="flex-1 flex flex-col items-center">
        <div className="flex justify-between items-center w-full mb-6">
           <h3 className="text-xl font-black text-slate-800 dark:text-white uppercase tracking-tighter">Lucky Draw</h3>
           {!isLastMember && (
             <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-2xl border border-slate-200 dark:border-white/5">
                <button onClick={() => setDrawMode('spin')} className={`px-4 py-1.5 rounded-xl text-[10px] font-black tracking-widest transition-all ${drawMode === 'spin' ? 'bg-white dark:bg-slate-700 text-brand-600 shadow-sm' : 'text-slate-400'}`}>SPIN</button>
                <button onClick={() => setDrawMode('manual')} className={`px-4 py-1.5 rounded-xl text-[10px] font-black tracking-widest transition-all ${drawMode === 'manual' ? 'bg-white dark:bg-slate-700 text-brand-600 shadow-sm' : 'text-slate-400'}`}>MANUAL</button>
             </div>
           )}
        </div>

        <div className="relative mb-8 flex items-center justify-center" style={{ width: 350, height: 350 }}>
          {drawMode === 'spin' || isLastMember ? (
            <div style={{ position: 'relative', width: 350, height: 350, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
               <div className="absolute inset-[-4px] rounded-full bg-gradient-to-tr from-brand-600 to-amber-400 opacity-20 blur-lg" />
               <Pointer />
               <canvas ref={canvasRef} width={WHEEL_SIZE} height={WHEEL_SIZE} style={{ width: 350, height: 350, cursor: 'pointer' }} />
               {isLastMember && <div className="absolute inset-0 bg-white/5 backdrop-blur-[2px] rounded-full flex items-center justify-center border-2 border-dashed border-emerald-500/30 text-emerald-500 font-black text-[10px] tracking-[0.2em] uppercase">Auto-Assign Next</div>}
            </div>
          ) : (
            <div className="w-[350px] h-[350px] rounded-[48px] bg-slate-50 dark:bg-slate-900/50 border-2 border-dashed border-slate-200 dark:border-white/10 flex flex-col items-center justify-center p-8 text-center">
               <div className="text-4xl mb-4">🎯</div>
               <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-6">Select a Member from the list</p>
               {manualWinnerId ? (
                 <div className="bg-brand-500/10 p-4 rounded-3xl border border-brand-500/20 w-full scale-in-center">
                    <p className="text-xs font-black text-brand-600 uppercase tracking-widest">{eligibleMembers.find(e => e.member?._id === manualWinnerId)?.member?.name}</p>
                 </div>
               ) : <div className="p-4 rounded-3xl bg-slate-100 dark:bg-slate-800 text-[10px] font-black text-slate-300 tracking-widest">NO ONE SELECTED</div>}
            </div>
          )}
        </div>

        <button onClick={conductDraw} disabled={spinning || loading} className={`w-full max-w-[350px] h-16 rounded-[24px] font-black text-sm tracking-[0.25em] uppercase shadow-xl transition-all active:scale-95 ${isLastMember ? 'bg-emerald-500' : 'bg-slate-900'} text-white`}>
          {loading ? '...' : spinning ? '🍀 Spinning Luck' : isLastMember ? '✨ Assign Winner' : drawMode === 'spin' ? '🚀 Start Spin Draw' : '🎯 Assign Selected'}
        </button>
      </div>

      <div className="w-full md:w-[320px] shrink-0">
        <div className="bg-white dark:bg-slate-900/40 rounded-[32px] border border-slate-100 dark:border-white/5 overflow-hidden shadow-sm">
          <div className="p-6 border-b border-slate-50 dark:border-white/5">
             <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Participants</p>
             <p className="text-xl font-black text-slate-800 dark:text-white">{eligibleMembers.length} Joined</p>
          </div>
          <div className="max-h-[360px] overflow-y-auto no-scrollbar pb-4">
             {eligibleMembers.map((e, i) => {
               const isSel = manualWinnerId === e.member?._id;
               return (
                 <div key={e._id || i} onClick={() => drawMode === 'manual' && setManualWinnerId(e.member?._id)} className={`flex items-center gap-4 p-4 cursor-pointer transition-colors ${isSel ? 'bg-brand-500/5' : 'hover:bg-slate-50 dark:hover:bg-white/5'}`}>
                   <div className="w-2 h-2 rounded-full" style={{ backgroundColor: SEG_PALETTES[i % SEG_PALETTES.length].bg }} />
                   <div className="flex-1 min-w-0"><p className={`text-xs font-black truncate ${isSel ? 'text-brand-600' : 'text-slate-700 dark:text-slate-300'}`}>{e.member?.name}</p></div>
                   {isSel && <div className="w-4 h-4 bg-brand-500 rounded-full flex items-center justify-center"><svg className="w-2.5 h-2.5 text-white" fill="currentColor" viewBox="0 0 20 20"><path d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" /></svg></div>}
                 </div>
               );
             })}
          </div>
        </div>
      </div>

      {showModal && (
        <WinnerModal 
          winner={winner} 
          prizeAmount={prizeAmount} 
          cycleLabel={cycleLabel} 
          onClose={() => {
            setShowModal(false);
            setWinner(null);
            if (onCloseDraw) onCloseDraw();
          }} 
        />
      )}
    </div>
  );
}
