import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import api from '../utils/api';
import LoadingSpinner from '../components/common/LoadingSpinner';
import { format } from 'date-fns';
import { TrophyIcon, BanknotesIcon, ArrowRightOnRectangleIcon, UserIcon } from '@heroicons/react/24/outline';
import { generateCycles } from '../utils/cycleHelper';

export default function MemberDashboardPage() {
  const { user, logout } = useAuth();
  const [data, setData] = useState({ groups: [], winners: [], payments: [] });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api.get('/member-portal/dashboard')
      .then(res => setData(res.data.data))
      .catch(err => console.error(err))
      .finally(() => setLoading(false));
  }, []);

  if (loading) return <LoadingSpinner />;

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-gray-950 flex flex-col font-sans">
      {/* Header */}
      <header className="bg-white dark:bg-gray-900 border-b border-slate-200 dark:border-white/5 sticky top-0 z-40">
        <div className="max-w-5xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-emerald-500 rounded-lg flex items-center justify-center">
              <UserIcon className="w-5 h-5 text-white" />
            </div>
            <div>
              <p className="font-bold text-slate-900 dark:text-white leading-none">{user.name}</p>
              <p className="text-[10px] text-slate-500 uppercase tracking-wider mt-0.5">Member Portal</p>
            </div>
          </div>
          <button onClick={logout} className="p-2 hover:bg-red-50 dark:hover:bg-red-900/10 text-slate-400 hover:text-red-500 rounded-xl transition-colors">
            <ArrowRightOnRectangleIcon className="w-5 h-5" />
          </button>
        </div>
      </header>

      <main className="flex-1 max-w-5xl mx-auto w-full px-4 py-8 space-y-6">
        
        {/* Quick Stats */}
        <div className="grid grid-cols-2 gap-4">
          <div className="bg-white dark:bg-gray-900 border border-slate-100 dark:border-white/5 rounded-2xl p-5 shadow-sm">
            <div className="flex items-center gap-3 mb-2">
              <BanknotesIcon className="w-5 h-5 text-emerald-500" />
              <p className="font-bold text-slate-500 text-sm">Active Groups</p>
            </div>
            <p className="text-3xl font-black text-slate-800 dark:text-white">{data.groups.length}</p>
          </div>
          <div className="bg-gradient-to-br from-gold-500 to-amber-600 rounded-2xl p-5 shadow-sm text-white">
            <div className="flex items-center gap-3 mb-2">
              <TrophyIcon className="w-5 h-5" />
              <p className="font-bold text-gold-100 text-sm">Draws Won</p>
            </div>
            <p className="text-3xl font-black">{data.winners.filter(w => w.member?._id === user._id).length}</p>
          </div>
        </div>

        {/* My Groups details */}
        <div>
          <h2 className="text-lg font-black text-slate-800 dark:text-white mb-4 uppercase tracking-tighter">My Chit Groups</h2>
          {data.groups.length === 0 ? (
            <div className="text-center py-10 text-slate-400 text-sm italic border border-dashed border-slate-200 dark:border-white/10 rounded-2xl">
              You are not enrolled in any chit fund groups yet.
            </div>
          ) : (
            <div className="space-y-4">
              {data.groups.map(group => {
                const groupPayments = data.payments.filter(p => p.chitGroup?._id === group._id);
                const paidCount = groupPayments.filter(p => p.status === 'paid').length;
                const cycles = generateCycles(group);
                const isWinnerMsg = data.winners.find(w => w.chitGroup?._id === group._id && w.member?._id === user._id) 
                                      ? '🎉 You have won a draw in this group!' : '';
                return (
                  <div key={group._id} className="bg-white dark:bg-gray-900 border border-slate-100 dark:border-white/5 rounded-[24px] p-6 shadow-sm">
                    <div className="flex flex-col md:flex-row justify-between md:items-center gap-4 border-b border-slate-50 dark:border-white/5 pb-4 mb-4">
                       <div>
                         <h3 className="text-xl font-bold text-slate-900 dark:text-white">{group.name}</h3>
                         <p className="text-xs text-slate-500 mt-1">{cycles[group.currentMonth - 1]?.label || `Month ${group.currentMonth}`} of {group.totalMonths}</p>
                       </div>
                       <div className="bg-slate-50 dark:bg-slate-800 rounded-xl p-3 flex gap-4 min-w-fit">
                          <div>
                            <p className="text-[10px] text-slate-400 uppercase font-bold text-center">Monthly</p>
                            <p className="font-black text-slate-700 dark:text-slate-300">₹{group.monthlyAmount}</p>
                          </div>
                          <div className="w-px bg-slate-200 dark:bg-gray-700" />
                          <div>
                             <p className="text-[10px] text-slate-400 uppercase font-bold text-center">Paid</p>
                             <p className="font-black text-emerald-600 dark:text-emerald-400">{paidCount}/{group.currentMonth}</p>
                          </div>
                       </div>
                    </div>
                    {isWinnerMsg && <div className="text-sm font-bold text-brand-600 dark:text-brand-400 bg-brand-50 dark:bg-brand-900/20 px-4 py-2 rounded-lg mb-4 inline-block">{isWinnerMsg}</div>}
                    <div className="grid grid-cols-5 md:grid-cols-10 gap-2 mt-4">
                      {Array.from({ length: group.currentMonth }).map((_, i) => {
                        const mnt = i + 1;
                        const pmt = groupPayments.find(p => p.monthIndex === mnt);
                        const isPaid = pmt?.status === 'paid';
                        return (
                          <div key={mnt} className={`h-12 rounded-lg border-2 flex items-center justify-center font-black text-xs ${isPaid ? 'border-emerald-500 bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600' : 'border-slate-200 dark:border-slate-700 text-slate-400'}`}>
                            M{mnt}
                          </div>
                        );
                      })}
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>

        {/* Global Winners */}
        <div>
           <div className="flex items-center gap-2 mb-4">
             <TrophyIcon className="w-5 h-5 text-gold-500" />
             <h2 className="text-lg font-black text-slate-800 dark:text-white uppercase tracking-tighter">Recent Winners</h2>
           </div>
           
           <div className="bg-white dark:bg-gray-900 border border-slate-100 dark:border-white/5 rounded-[24px] overflow-hidden shadow-sm">
             {data.winners.length === 0 ? (
                <div className="p-8 text-center text-slate-400 text-sm">No draws have been conducted yet.</div>
             ) : (
                <div className="divide-y divide-slate-50 dark:divide-white/5">
                  {data.winners.map(w => (
                    <div key={w._id} className="p-4 sm:p-6 flex items-center gap-4">
                      <div className="w-12 h-12 bg-gradient-to-br from-gold-400 to-amber-600 rounded-full flex items-center justify-center text-white font-bold shadow-glow-gold flex-shrink-0">
                        {w.member?.name?.[0]}
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="flex justify-between items-start">
                          <p className="font-bold text-slate-900 dark:text-white truncate text-lg pr-4">{w.member?.name}</p>
                          <p className="font-black text-emerald-600 dark:text-emerald-400">₹{w.prizeAmount?.toLocaleString()}</p>
                        </div>
                        <div className="flex flex-col sm:flex-row sm:items-center gap-1 sm:gap-3 mt-1">
                          <p className="text-xs text-slate-500">{w.chitGroup?.name}</p>
                          <span className="hidden sm:inline text-slate-300">•</span>
                          <p className="text-xs font-bold text-brand-600">Month {w.monthIndex}</p>
                          <span className="hidden sm:inline text-slate-300">•</span>
                          <p className="text-xs text-slate-400">{format(new Date(w.drawDate), 'dd MMM yyyy')}</p>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
             )}
           </div>
        </div>

      </main>
    </div>
  );
}
